import{_ as o,o as a,c as e,a2 as r}from"./chunks/framework.BQ1gajhD.js";const h=JSON.parse('{"title":"乾清宫","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/qianqing-gong.md","filePath":"landmarks/forbidden-city/qianqing-gong.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/qianqing-gong.md"};function l(i,t,s,d,g,u){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="乾清宫" tabindex="-1">乾清宫 <a class="header-anchor" href="#乾清宫" aria-label="Permalink to &quot;乾清宫&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1547904156-6b44fcefe351?w=1200&amp;q=80" alt="乾清宫"></p><blockquote><p>正大光明匾下，藏着帝国的继承秘密。这里是天子的寝宫，也是明朝最惊心动魄的宫变现场。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>乾清宫是内廷后三宫之首，位于乾清门内，是紫禁城&quot;内廷&quot;区域的起点。&quot;乾清&quot;取《道德经》&quot;天得一以清&quot;之意，与后方的坤宁宫（&quot;坤得一以宁&quot;）相对，乾为天、坤为地，帝居乾清、后居坤宁，是&quot;天清地宁&quot;的宇宙图式在宫廷建筑中的映射。</p><p>明代，乾清宫是皇帝正式的<strong>寝宫兼日常理政之所</strong>——皇帝在此居住、批阅奏章、召见大臣，是真正的&quot;天子起居之地&quot;。清初顺治、康熙两帝沿用此制，直到雍正帝移居养心殿后，乾清宫才转为接见臣工、举行内廷典礼的场所。</p><p>乾清宫建成于明永乐十八年（1420年），现存建筑为清嘉庆三年（1798年）重建。殿内高悬的**&quot;正大光明&quot;匾额**，是顺治帝御笔、康熙帝摹勒上石，它背后曾藏着清朝最核心的政治机密——秘密立储诏书。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面阔</strong></td><td style="text-align:left;">九间（内廷最高规格）</td></tr><tr><td style="text-align:left;"><strong>进深</strong></td><td style="text-align:left;">五间</td></tr><tr><td style="text-align:left;"><strong>屋顶</strong></td><td style="text-align:left;">重檐庑殿顶</td></tr><tr><td style="text-align:left;"><strong>殿内匾额</strong></td><td style="text-align:left;">&quot;正大光明&quot;（顺治御笔，康熙摹刻）</td></tr><tr><td style="text-align:left;"><strong>明代暖阁</strong></td><td style="text-align:left;">殿内分隔为上下两层、九室，设床27张</td></tr><tr><td style="text-align:left;"><strong>台基</strong></td><td style="text-align:left;">单层汉白玉须弥座，月台前设江山社稷金殿</td></tr></tbody></table><p>乾清宫面阔九间、重檐庑殿，规制与太和殿相仿而尺度略小，体现了&quot;前朝宏大、内廷精严&quot;的设计逻辑。殿内正中设宝座，上悬&quot;正大光明&quot;匾，两侧楹联为&quot;克宽克仁，皇建其有极；惟精惟一，道积于厥躬&quot;。</p><p>明代乾清宫内部并非一览无余的大殿，而是分隔为<strong>上下两层的九间暖阁</strong>，设床27张，皇帝每晚随意择一处安寝，不令外人知晓——这是出于防范刺杀的安全考虑。殿前月台上陈设着<strong>江山社稷金殿</strong>（两座小型金制亭式陈设）和日晷、嘉量，象征皇帝对天下时空的掌控。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="正大光明-匾后的秘密立储" tabindex="-1">&quot;正大光明&quot;匾后的秘密立储 <a class="header-anchor" href="#正大光明-匾后的秘密立储" aria-label="Permalink to &quot;&quot;正大光明&quot;匾后的秘密立储&quot;">​</a></h3><p>清代最大的政治隐患之一是皇位继承。康熙朝&quot;九子夺嫡&quot;的惨烈教训让雍正帝痛定思痛，创立了<strong>秘密立储制度</strong>：皇帝生前将选定的继承人名字写入密诏，一藏于&quot;正大光明&quot;匾后，一随身携带。皇帝驾崩后，由王公大臣共同开启两份诏书核对，宣布新君。从此，皇子们不再知道谁是储君，也就无法结党倾轧。这块匾额背后，先后藏过乾隆、嘉庆、道光、咸丰四朝的秘密立储诏书——它是中国皇位继承史上最精巧的制度设计，就挂在乾清宫最显眼的位置。</p><h3 id="壬寅宫变-宫女们的殊死一搏" tabindex="-1">壬寅宫变：宫女们的殊死一搏 <a class="header-anchor" href="#壬寅宫变-宫女们的殊死一搏" aria-label="Permalink to &quot;壬寅宫变：宫女们的殊死一搏&quot;">​</a></h3><p>明嘉靖二十一年（1542年）十月二十一日深夜，乾清宫内发生了中国宫廷史上最骇人听闻的事件：以杨金英为首的十六名宫女，趁嘉靖帝熟睡之际，用绳索套住他的脖颈试图将其勒死。宫女们因紧张将绳结打成死扣，未能勒紧，一名宫女慌忙跑去报告皇后，嘉靖帝被救回，但昏厥多日。事后十六名宫女全部被凌迟处死，牵连端妃、宁嫔同遭极刑。史称&quot;壬寅宫变&quot;。此事的起因众说纷纭——一说嘉靖帝为炼丹长期虐待宫女、采补宫人，宫女们不堪折磨而铤而走险。这场宫变之后，嘉靖帝彻底搬离乾清宫，移居西苑（今中南海）长达二十余年不再回宫，乾清宫一度空置。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>&quot;正大光明&quot;匾额</strong>：殿内正中最醒目的陈设，想象匾后曾藏匿帝国命运的那份密诏。</li><li><strong>殿内宝座与楹联</strong>：透过殿门可见金漆宝座与&quot;克宽克仁&quot;楹联，是内廷正殿的庄严气象。</li><li><strong>月台陈设</strong>：殿前月台上的江山社稷金殿、日晷、嘉量，是皇权&quot;一统江山&quot;的微缩象征。</li><li><strong>暖阁制度的痕迹</strong>：殿内空间的分隔格局，保留着明代&quot;九室二十七床&quot;的安保设计遗意。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>与太和殿对比</strong>：乾清宫面阔同为九间，但尺度明显小于太和殿——外朝的&quot;公&quot;与内廷的&quot;私&quot;，在建筑体量上一目了然。</li><li><strong>别只看殿内</strong>：殿前月台上的铜鹤、铜龟、江山社稷金殿常被忽略，值得绕行细看。</li><li><strong>最佳拍摄</strong>：从乾清门方向正面拍摄，可框住乾清门、月台、大殿的完整纵深。</li><li><strong>联想养心殿</strong>：雍正之后的皇帝实际居住在养心殿（西六宫南侧，目前未完全开放），乾清宫更多承担礼仪功能——了解这层转变，才能读懂内廷的空间逻辑。</li></ul><hr><p><strong>📍 位置</strong>：内廷中轴线首殿，乾清门内 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/baohe-dian.html">保和殿</a>（经乾清门入内廷） <strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/jiaotai-dian.html">交泰殿</a><strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',22)])])}const f=o(n,[["render",l]]);export{h as __pageData,f as default};
